oxy_webhelp_navlinks = {"github_set_up_backup_loc-d27243e32719":{"topics":[{"title":"Evaluate backup options for GitHub","shortdesc":"<p class=\"shortdesc\">It is important to evaluate the backup options for GitHub to align with the         performance and data retrieval needs. Key considerations include the choice of cloud         provider, storage locations, access tiers, and network security configurations.<\/p>","href":"github\/github_evaluate_backup_options.html","attributes":{"data-id":"github_evaluate_backup_options"},"menu":{"hasChildren":false},"tocID":"github_evaluate_backup_options-d27243e32732","next":"github_evaluate_backup_options-d27243e32732"},{"title":"User permissions for GitHub backup location","shortdesc":"<p class=\"shortdesc\">Configuring a GitHub backup location in <span class=\"ph\">RSC<\/span> requires a role with         specific permissions to manage cloud accounts and archival settings. These permissions         enable you to connect the Azure or AWS cloud accounts used for storage and compute, and to         configure the archival locations where GitHub repository data will be stored.<\/p>","href":"github\/github_user_perms_backup_loc.html","attributes":{"data-id":"github_user_perms_backup_loc"},"menu":{"hasChildren":false},"tocID":"github_user_perms_backup_loc-d27243e32791","topics":[]},{"title":"Configure GitHub backup location","shortdesc":"<p class=\"shortdesc\">You must create a backup location for storing snapshots of GitHub repositories.         Additionally, you can configure a private or service endpoint to back up snapshots to the         backup location.<\/p>","href":"github\/github_configure_backup_loc.html","attributes":{"data-id":"github_configure_backup_loc"},"menu":{"hasChildren":false},"tocID":"github_configure_backup_loc-d27243e32805","next":"github_configure_backup_loc-d27243e32805"}]}};